#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
ll n,m,a[N],cha[N],tr[N],tr2[N];
void add(int x,ll num)
{
	for(int i=x;i<=n;i+=(i&(-i)))
	{
		tr[i]+=num;
		tr2[i]+=(num*x);
	}
}
ll query(int x)
{
	ll sum=0;
	for(int i=x;i>0;i-=(i&(-i)))
	{
		sum+=(x*tr[i]+tr[i]-tr2[i]);
	}
	return sum;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		cha[i]=a[i]-a[i-1];
		add(i,cha[i]-cha[i-1]);
	}
	for(int i=1;i<=m;i++)
	{
		int op;
		cin>>op;
		if(op==1)
		{
			ll l,r,k,d;
			cin>>l>>r>>k>>d;
			add(l,k);
			add(l+1,d-k);
			add(r+1,-((r-l+1)*d+k));
			add(r+2,k+(r-l)*d);
		}
		else
		{
			ll p;
			cin>>p;
			cout<<query(p)<<"\n";
		}
	}
	return 0;
	return 0;
}
